const express = require('express');
const winston = require('winston');
const morgan = require('morgan');

const app = express();
app.use(morgan('combined'));
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf((info) => `${info.timestamp} - ${info.method} - ${info.url} - ${info.status} - ${info.statusText} - ${JSON.stringify(info.user)} - ${info.ip} - ${Object.keys(info.headers).length > 0 ? JSON.stringify(info.headers) : 'No headers provided'}`)
  ),
  transports: [
    new winston.transports.File({ filename: 'combined.log', handleExceptions: true }),
    new winston.transports.Console()
  ],
});

app.use((req, res, next) => {
  const user = req.body;
  logger.info({
    timestamp: Date.now(),
    method: req.method,
    url: req.url,
    status: '',
    statusText: '',
    user,
    ip: req.ip,
    headers: req.headers
  });
  next();
});

app.post('/audit', (req, res) => {
  const auditData = req.body;
  logger.info({
    timestamp: Date.now(),
    method: 'POST',
    url: '/audit',
    status: '',
    statusText: '',
    user: { username: req.body.username },
    ip: req.ip,
    headers: { Authorization: req.headers.authorization }
  });
  res.status(200).send('Audit logged successfully');
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});